"""
MKT Context Commentary — Psalms chapters 55–61
Run: python3 scripts/zc-context-psalms-55-61.py

Source data used:
- data/interlinear/psalms.json
- data/translation/draft/mediating/psalms.json (MKT text)
- data/commentary/ellicott/psalms.json (philological background)
- data/commentary/jfb/psalms.json (historical context)

Key decisions in this range:
- Ps 55: traditionally linked to Ahithophel's betrayal of David during Absalom's revolt (2 Sam 15–17);
  'companion' language (vv13–14, 20–21) suits that narrative; the threefold daily prayer (v17) is a
  pre-exilic antecedent to the fixed Jewish prayer hours (Shacharit, Mincha, Maariv)
- Ps 56: superscription links to David's time at Gath / feigned madness before Achish (1 Sam 21:10–15);
  'miktam' genre (also Pss 16, 56–60) — meaning uncertain, possibly 'golden poem' or 'inscribed poem'
- Ps 57: 'Al-tashheth' (al-tashḥet = 'Do Not Destroy') is a tune title also used for Pss 58–59;
  'shadow of your wings' (v1) is temple cherubim imagery; the dawn-rousing (v8) is a distinctive motif
- Ps 58: the addressees of v1 (elim / 'elohim) debated — divine council, human rulers, or both; the
  serpent/cobra imagery (vv4–5) reflects ancient herpetological observation
- Ps 59: superscription links to 1 Sam 19:11–18 (Saul's agents watching the house; Michal's rescue);
  the 'do not kill them' petition (v11) is a deliberate appeal for preserved witness rather than obliteration
- Ps 60: superscription links to the Aram/Edom campaigns (2 Sam 8:3, 13; 1 Chr 18:3, 12); the oracle
  (vv6–8) asserts YHWH's territorial sovereignty over all the contested land; Ps 108:7–13 duplicates vv5–12
- Ps 61: the king-prayer (vv6–7) suggests a cultic setting where the king's welfare was publicly petitioned;
  'from the ends of the earth' (v2) signals temple-absent distress, not literal geography
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

PSALMS = {
  "55": {
    "1": '<p>The superscription designates Psalm 55 a <em>maskil</em> — the same genre term used for Psalms 32, 42, 44–45, 52–55, 74, 78, 88–89, and 142, typically translated "instructional poem" or "contemplation." Many commentators associate its contents with the Absalom revolt and the defection of Ahithophel, David\'s close counselor who joined the rebellion (2 Sam 15–17). The betrayal language of vv. 12–14 and 20–21 fits that narrative precisely — a trusted companion who turned an intimate relationship into a weapon. The poem is performed with <em>nĕgînôt</em> (stringed instruments), placing it in formal temple or levitical musical practice.</p>',
    "2": '<p>"I am troubled in my lament and I am agitated" — <em>ʾāhîmāh bĕśîḥî</em>. The verb <em>hāmâ</em> (to make a noise, murmur, roar) describes the inward turbulence of distress — a churning emotional state that cannot be stilled. The same root describes the roaring of armies (Ps 46:6), the tumult of the sea (Ps 46:3), and the groaning of the hungry (Ps 59:15). The psalmist\'s inner state matches the violence of the outer threat; the prayer is not composed but raw and urgent.</p>',
    "3": '<p>"The threatening voice of the enemy, the oppressive presence of the wicked" — <em>qôl ʿôyēb</em> (voice of the enemy) and <em>ʿăqat rāšāʿ</em> (the pressing/oppression of the wicked). The combination of audible threat and physical oppressive pressure captures two modes of intimidation: the verbal and the social. In a court or legal context, "the voice of the enemy" might specifically mean false accusation or slander before a tribunal — a weapon the Psalter frequently invokes (Pss 22:8; 42:10; 43:2).</p>',
    "4": '<p>"My heart is writhing in anguish within me" — <em>libbî yāḥîl bĕqirbî</em>. The verb <em>ḥîl</em> describes the convulsive writhing of labor pains (Isa 13:8; 26:17; Jer 22:23; Mic 4:10) and earthquake (Ps 97:4); applied to the heart, it conveys not mere sadness but a violent interior upheaval. "The terrors of death have fallen on me" — <em>ʾêmôt māwet</em> (terrors of death): in ANE thought, the realm of death (<em>Sheol</em>) exerted a gravitational pull even on the living through extreme suffering; the dying person was already partly claimed by the underworld.</p>',
    "5": '<p>"Fear and trembling have overtaken me, and shuddering has covered me over" — the triad <em>yirʾāh</em> (fear), <em>rāʿad</em> (trembling), and <em>pallāṣût</em> (shuddering, horror) describes the full-body physical response to mortal threat. The phrase <em>yirʾāh wārāʿad</em> (fear and trembling) appears in the NT at Philippians 2:12, where Paul applies it to the moral seriousness of the believer\'s working out of salvation — the same language for confronting ultimate stakes. <em>Pallāṣût</em> (shuddering) occurs only here and at Isa 21:4, where the watchman is overcome with horror at the vision of Babylon\'s fall.</p>',
    "6": '<p>"If only I had wings like a dove! I would fly away and find rest" — the dove was associated with peace, purity, and swift flight in the ANE. Egyptian wisdom texts use bird-flight as an image of escape from distress. The dove is the bird of peace offerings (<em>tôr</em> or <em>yônāh</em>) and appears throughout the Psalter as a vulnerable, beloved creature (Pss 68:13; 74:19). The wish for wings is not a fantasy of power (eagle-wings, as in Isa 40:31) but of quiet escape — the dove as the creature that retreats rather than fights. The wilderness (<em>midbār</em>) in v. 7 is not desolate wasteland but uninhabited space free from urban corruption.</p>',
    "7": '<p>"I would flee far away; I would make my dwelling in the wilderness" — the wilderness (<em>midbār</em>) in the Psalter\'s imagination is a place of paradox: dangerous and yet free from the specific evil of the corrupt city. The Elijah tradition (1 Kgs 19:4–8) and the Mosaic tradition (Exod 3:1) both locate divine encounter in the wilderness — a place where the noise of social oppression is absent and YHWH\'s voice becomes audible. The speaker\'s wish is not to flee God but to flee the political intrigue and betrayal that has infected the city.</p>',
    "8": '<p>"I would hurry to my refuge from the driving wind and the storm" — <em>māḥôz lî</em> (a harbor/refuge for me) combined with <em>sûpāh</em> (storm, tempest) and <em>śāʿar</em> (raging wind). The storm imagery is picked up from ANE divine-warrior theology: storms are the chariot of the divine warrior (Pss 18:10; 29:3–9; Hab 3:8). Here the speaker flees the storm rather than riding it — the contrast between the divine warrior who commands the storm and the vulnerable human who needs shelter from it.</p>',
    "9": '<p>"Confuse them, O Lord, split their tongues apart" — <em>ballēʿ ʾadonāy pallag śĕpātām</em>. The first verb <em>ballaʿ</em> (to swallow up, confuse, destroy) and the second <em>pallag</em> (to divide, split) together invoke the Babel narrative (Gen 11:7–9), where YHWH confused the tongues of those who conspired against him. The prayer is for a Babel-like dissolution of the conspiracy: if tongues are split, coordination is broken. The violence and contention (<em>ḥāmās wĕrîb</em>) in the city are what make this prayer urgent.</p>',
    "10": '<p>"Day and night they patrol its walls; iniquity and trouble are entrenched within it" — <em>yômam wālaylāh yĕsôbĕbûhā ʿal-ḥômōtêhā</em>. The normal city watchman (<em>šōmēr</em>) guards the walls against external threat; here the watchmen are themselves the agents of wickedness. The city that should be a place of order protected by YHWH\'s covenant has become a place where lawlessness is the constant patrol. <em>ʿĀwel</em> (iniquity) and <em>ʿāmāl</em> (trouble, toil, misery) are its permanent residents — a biting reversal of what a covenant city should be.</p>',
    "11": '<p>"Ruin is entrenched at its center; oppression and fraud never leave its public spaces" — <em>hawwôt bĕqirbāh</em> (ruin/destruction in its interior) and <em>tôk ûmirmāh</em> (oppression and fraud) in the <em>rĕḥōbôt</em> (public squares, market spaces). In ANE city design, the <em>rĕḥôb</em> (plaza/square) was the site of legal proceedings, commerce, and community life — the most public space in the city. Fraud and oppression colonizing this space means the covenant functions of city life (justice, fair commerce, community protection) have been wholly subverted. The city exists as an anti-covenant space.</p>',
    "12": '<p>"For it is not an enemy who insults me — that I could endure; nor is it someone who hates me who has risen up against me — from that I could hide" — the rhetorical move is precise: external hostility is manageable because it is legible. The ANE code of honor assumed declared enemies — known opponents with known motives. Against such threats, one could take defensive measures or invoke legal protections. The insult of a known enemy could be answered with equal force or absorbed within the logic of public contest. It is the betrayal by the trusted insider that has no defense.</p>',
    "13": '<p>"But it is you — a person like me, my peer, my companion, the one I confided in" — <em>ʾattāh ʾĕnôš kĕʿerkî ʾallûpî ûmĕyuddāʿî</em>. Three terms of closeness: <em>kĕʿerkî</em> (my equal, my match — the same social standing), <em>ʾallûp</em> (intimate friend, one in whom confidence is placed — from the root for learning and familiarity), and <em>mĕyuddāʿî</em> (the one I know, my known one — a term of deep personal acquaintance). The progression moves from social equality to emotional intimacy to intellectual trust. In the Absalom narrative, Ahithophel was David\'s most trusted counselor; his counsel was "as if one consulted the word of God" (2 Sam 16:23).</p>',
    "14": '<p>"We shared deep, sweet conversation together; together we walked in God\'s house among the festival crowd" — <em>ʾăšer yaḥdāw namtîq sôd bĕbêt ʾĕlōhîm nĕhalēk bĕrāgeš</em>. The word <em>sôd</em> (intimate counsel, secret conversation) is the term for the divine council in which the prophets stand (Jer 23:18, 22; Amos 3:7; Ps 89:7) — the closest possible circle of confidential relationship. To share <em>sôd</em> was to be admitted to the inner chamber of trust. "Festival crowd" (<em>rāgeš</em> — the tumultuous gathering of pilgrims) suggests the relationship was formed in the context of shared temple worship — the betrayal is thus also a desecration of that sacred bond.</p>',
    "15": '<p>"Let death ambush them; let them go down to Sheol alive" — the imprecation draws on the Korah narrative (Num 16:31–33), where the ground opened and swallowed the rebels "alive" (<em>ḥayyîm</em>) into Sheol — the most vivid OT depiction of divine judgment overtaking the wicked without the dignity of a normal death. The prayer is that the conspirators meet a similarly exemplary end: not quiet death but consumed by the power they were defying. Such imprecations are covenant curses invoked against covenant violators — the same logic as the treaty-curse formulas of Deuteronomy 27–28.</p>',
    "16": '<p>"As for me, I will call upon God, and the LORD will rescue me" — the sharp contrast (<em>ʾănî ʾel-ʾĕlōhîm ʾeqrāʾ</em>) turns from imprecation to personal commitment. The verb <em>qārāʾ</em> (to call, cry out) is the Psalter\'s characteristic verb for prayer in extremity (Pss 4:3; 17:6; 18:6; 22:2; 31:17; 34:6, 17). The name YHWH follows deliberately — not merely God as a general divine being but the covenant God of Israel whose personal name carries the weight of all prior acts of rescue.</p>',
    "17": '<p>"Evening and morning and at noon I cry out my lament and sigh; and he hears my voice" — the triple prayer rhythm (<em>ʿereb wĕbōqer wĕṣohŏrāyim</em>) is an early attestation of what became the fixed Jewish prayer hours: <em>Maariv</em> (evening), <em>Shacharit</em> (morning), and <em>Mincha</em> (afternoon/noon). Daniel 6:10 establishes the same three-daily pattern during the Babylonian exile, suggesting the custom was ancient and not exilic invention. In the ANE, marking prayer three times per day was a discipline of covenant loyalty — a daily rhythm of address to the covenant God. The pattern also echoes the divine creation of time markers (evening, morning — Gen 1) as the framework within which covenant life unfolds.</p>',
    "18": '<p>"He ransoms me safely from the battle I am in, for they are many who oppose me" — <em>pādāh bĕšālôm napšî miqqĕrāb-lî</em>. The verb <em>pādāh</em> (redeem, ransom) carries the economic-legal sense of paying the price to recover something held captive. Applied to divine rescue, it means YHWH pays the full cost to bring the speaker safely out of the siege — <em>bĕšālôm</em> (safely, in wholeness, with shalom intact) — not merely survival but restoration of the whole person. "Battle" (<em>qĕrāb</em>) can mean military combat but also legal contest — the full-court press of organized opposition.</p>',
    "19": '<p>"God will hear and afflict them, the one who is enthroned from of old" — <em>qōšēb qedem</em> (the one enthroned from antiquity/from of old). This divine attribute — ancient sovereignty over time — contrasts with the conspirators\' momentary power. The phrase echoes the language of Ps 29:10 (YHWH sits enthroned over the flood, forever) and Ps 93:2 (your throne is established from of old). "Because they show no sign of change (<em>ʾên ḥălîpôt lāhem</em>) and have no fear of God" — the Hebrew means literally "there are no changes for them" — they are locked in an unchanging wickedness; the <em>yirʾat ʾĕlōhîm</em> (fear of God) that would prompt repentance is absent.</p>',
    "20": '<p>"He raised his hand against those who were at peace with him; he broke his covenant" — <em>šillah yādāyw bišlōmāyw ḥillēl bĕrîtô</em>. "Those who were at peace with him" (<em>šĕlōmāyw</em>) are those with whom a covenant of peace existed — the same covenant partner language used for treaties (<em>baʿal bĕrît</em>, "lords of covenant"). "He broke his covenant" (<em>ḥillēl bĕrîtô</em>) — <em>ḥillēl</em> means to profane, defile, or violate something sacred. A covenant had the character of a sacred oath enforced by divine witness; to break it was an act of sacrilege as much as a political offense. This is the deepest charge against the betraying companion — not merely personal treachery but covenant violation before God.</p>',
    "21": '<p>"His words were smoother than butter, yet war was in his heart; his speech was softer than oil, but it was all drawn swords" — the antithesis between smooth speech and violent intent is one of the most striking images in the Psalter. <em>Māʾăsuppāyw ḥālĕqû miḥemʾāh</em> (his words were smoother than cream/butter) and <em>rakkû dibĕrāyw miššemen</em> (his words were softer than oil). In ANE diplomatic language, smooth speech was the mark of court protocol and treaty negotiation; treaties were made with elaborate formal language precisely to bind parties. This smooth speaker uses treaty language while concealing "war in his heart" (<em>ûqĕrāb libbô</em>) — the archetype of the covenant traitor who invokes peace-language to enable attack. This verse became proverbial in the wisdom tradition for the danger of flattery (Prov 5:3–4; 26:23–28).</p>',
    "22": '<p>"Throw your burden onto the LORD, and he will hold you up" — <em>hašlēk ʿal YHWH yĕhābĕkā wĕhûʾ yĕkalkĕlekā</em>. The word <em>yĕhāb</em> (burden, what is given or assigned to one) is an Aramaic loanword appearing only here in the Hebrew Bible — its rarity suggests the verse may draw on wisdom tradition broader than the Israelite core texts. The verb <em>hišlîk</em> (to throw, cast) is forceful — not a gentle laying down but an active transfer of the burden\'s full weight onto YHWH. The concept was cited by Peter (1 Pet 5:7: "cast all your anxiety on him, because he cares for you"), though the Greek draws on a different idiom. The promise "he will never let the righteous be shaken" (<em>yānîṭ</em>, to totter) echoes Ps 15:5 and 16:8 — the covenant community has a stability the wicked lack.</p>',
    "23": '<p>"But you, O God, will bring them down into the pit of ruin; men of bloodshed and treachery will not reach half their days" — <em>bĕʾēr šaḥat</em> (the pit of destruction/Sheol\'s well) is a common OT image for the grave and the underworld (Pss 30:9; 103:4; Job 17:14; 33:18; Isa 38:17). "Not reach half their days" (<em>lōʾ yeḥĕṣû yĕmêhem</em>) — premature death as a divine judgment cutting off the wicked before their full allotted span. Proverbs and Deuteronomy promise long life to the righteous (Prov 3:2, 16; Deut 5:33) and early death to the wicked (Prov 10:27) — this verse applies that wisdom principle as a prayer-imprecation against the betrayer. The final clause "But I — I will trust in you" (<em>waʾănî ʾeḇṭaḥ-bāk</em>) is the psalm\'s final word, marking the transition from complaint and imprecation to renewed personal trust.</p>',
  },
  "56": {
    "1": '<p>The superscription links Psalm 56 to 1 Samuel 21:10–15: David fled to Gath to escape Saul, was recognized as Israel\'s king, and feigned madness before Achish the king to secure his release. Achish\'s court servants identified him as "the king of the land" for whom Israel sang "Saul has killed his thousands and David his ten-thousands" (1 Sam 21:11) — making David\'s presence at the Philistine court immediately dangerous. The musical heading "To the tune \'Dove of the Far-off Oaks\'" (<em>ʿal-yônat ʾēlem rĕḥōqîm</em>) is one of several such tune directions in the Psalter (cf. "Aijeleth Hashshahar" in Ps 22; "Shoshannim" in Pss 45, 69). The genre term <em>miktam</em> appears for Psalms 16 and 56–60; its meaning is debated — possibly "inscribed poem," "golden poem," or a technical term for a particular genre.</p>',
    "2": '<p>"My enemies trample on me all day long, for many are arrayed against me proudly" — the verb <em>šāʾap</em> (to trample, pant after with open mouth) describes aggressive pursuit with contemptuous intent. The phrase <em>bĕgāʾôn</em> (proudly, with arrogance) characterizes the enemies\' attitude: not merely hostile but disdainful. In the honor-shame culture of the ancient Near East, public contempt was a weapon as powerful as physical threat — to be openly despised by one\'s enemies was to be stripped of social worth. David at the Philistine court had no social standing; he was entirely vulnerable to the contempt of those around him.</p>',
    "3": '<p>"When I am afraid, I will put my trust in you" — <em>yôm ʾîrāʾ ʾănî ʾēlêkā ʾeḇṭaḥ</em>. This is one of the most honest confessional formulas in the Psalter: fear is not denied but confronted as the context within which trust is exercised. The statement does not say "I will not be afraid" but "when I am afraid, I will trust" — the trust is a response to fear, not an absence of it. This is not a claim of superior courage but a commitment to reorient toward God even in the midst of genuine fear. Second Temple piety valued this honest acknowledgment of vulnerability alongside covenant loyalty.</p>',
    "4": '<p>"In God — whose word I praise — in God I trust; I will not be afraid. What can a mere human being do to me?" — the refrain structure (repeated in vv. 10–11) creates a liturgical response pattern suggesting public or communal use. <em>Bāśār</em> (flesh, human being) is the Psalter\'s standard contrast to <em>ʾĕlōhîm</em> (God): flesh is mortal, frail, and limited — what can such a being ultimately do to one who is under divine protection? The same contrast appears in Isaiah 31:3 ("The Egyptians are human and not God; their horses are flesh and not spirit") and 2 Corinthians 10:3–4. The word <em>dāḇār</em> (word) is praised — trust is in the reliability of what God has spoken, not merely in an abstract divine power.</p>',
    "5": '<p>"All day long they distort my words; all their scheming is against me for evil" — <em>yĕʿaṣṣĕbû dĕbāray</em> (they twist, distort my words). The verb <em>ʿāṣab</em> in this form means to cause pain or distortion — the enemies take the psalmist\'s own words and warp them into something that can be used against him. This is the specific danger of the court context: in a foreign court without advocates, anything said could be misrepresented to the king. Accusations based on distorted speech were a standard legal weapon in the ancient world, and the Psalter frequently invokes them (Pss 27:12; 35:11; 109:2).</p>',
    "6": '<p>"They gather themselves to stir up trouble, they lie in ambush, they track my steps as they wait to take my life" — the sequence describes coordinated surveillance and ambush. The term <em>yāgûrû</em> (they lie in ambush, gather to watch) combined with <em>yišmĕrû ʿăqēbāy</em> (they watch my heels/tracks) evokes the careful surveillance of a hunted person. "As they wait to take my life" (<em>kaʾăšer qiwwû napšî</em>) — the hunting metaphor is extended: they lie in ambush with focused patience, waiting to spring. This situation mirrors the Saul-era persecution David experienced before coming to Gath.</p>',
    "7": '<p>"For their crime, should they escape? In wrath cast down the peoples, O God!" — the prayer for divine justice against the violent. The question is rhetorical: crime should not go unpunished. "Cast down the peoples" (<em>hôrēd ʿammîm</em>) — the appeal is not merely for personal deliverance but for YHWH to bring down the wicked as covenant judge. The extension to "the peoples" suggests that the threat has widened beyond one court to a broader situation — the Psalter frequently moves from the individual\'s crisis to the universal scope of divine justice.</p>',
    "8": '<p>"You have recorded my restless wandering; store my tears in your wineskin — are they not written in your book?" — one of the most tender images in the Psalter. <em>Nôd</em> (leather flask or wineskin) is proposed as the vessel for God to store the psalmist\'s tears — a liquid record of grief. The image assumes that every tear is of account to God, that suffering is not invisible to the one who made the sufferer. "My wandering (<em>nōdî</em>)" uses the same root as the flask — a wordplay: the wandering and the vessel share etymology. "Your book" (<em>bĕsipratĕkā</em>) — the divine record book in which human lives and deeds are inscribed (cf. Exod 32:32–33; Ps 139:16; Mal 3:16). The divine record-keeping of tears became a rich image in later Jewish and Christian devotion.</p>',
    "9": '<p>"On the day I call out, my enemies will turn back; this I know: God is on my side" — <em>zeh yādaʿtî kî ʾĕlōhîm lî</em> (this I know, for God is for me). The confident assertion of divine alliance — not a wish but a known certainty. In ANE diplomatic language, "being on someone\'s side" was the language of treaty alliance and patron-client loyalty. The psalmist asserts that the great Suzerain has entered the field on his behalf — the enemies\' attack is therefore an attack on the divine patron\'s client, which the patron must answer.</p>',
    "10": '<p>The refrain structure of vv. 10–11 repeats and slightly expands v. 4: "In God — whose word I praise — in the LORD — whose word I praise." The addition of the divine name YHWH alongside the general title <em>ʾĕlōhîm</em> intensifies the liturgical declaration. The doubling of the praise-formula emphasizes that it is the divine word (<em>dāḇār</em>) that is trustworthy — not merely the divine being in the abstract but the specific promises and covenants God has spoken. This is a creed-like affirmation of verbal revelation as the ground of trust.</p>',
    "11": '<p>"In God I trust; I will not be afraid. What can human beings do to me?" — the repeated refrain (cf. v. 4) closes the psalm\'s confession with a second hearing. The variation from v. 4 (<em>bāśār</em>, flesh → <em>ʾādām</em>, human being) shows a slightly different nuance: <em>bāśār</em> emphasizes mortality and physical weakness; <em>ʾādām</em> emphasizes creaturely status — both terms underline the radical disproportion between human threat and divine power. The question "what can they do?" is not naïve but theologically grounded: in light of divine protection, human hostility has a ceiling it cannot breach.</p>',
    "12": '<p>"I have made vows to you, O God, and I will fulfill them; I will offer you my thanksgiving" — the thanksgiving vow (<em>neder</em>) was a standard element of ancient Israelite prayer: in distress, one pledged a specific offering in exchange for divine rescue; upon rescue, one fulfilled that pledge publicly at the temple. This social-contractual dimension of prayer was not mere bargaining — it was a formal covenant exchange that publicly displayed the divine faithfulness when fulfilled. The thanksgiving offering (<em>tôdāh</em>) was a particular type of peace offering (Lev 7:12–15) accompanied by singing; Ps 56 itself may have been used as part of such a thanksgiving ceremony.</p>',
    "13": '<p>"For you have saved my life from death, and my feet from stumbling, so that I may walk before God in the light that belongs to the living" — the conclusion articulates the purpose of rescue: not mere survival but restored access to the divine presence (<em>hithalēk lipnê ʾĕlōhîm</em>, to walk before God). "The light that belongs to the living" (<em>bĕʾôr haḥayyîm</em>) is the condition of being alive in God\'s presence — the opposite of Sheol\'s darkness (Job 10:21–22; 38:17; Ps 88:12). The language echoes Job 33:30 ("to walk in the light of life") and anticipates John 8:12 ("I am the light of the world; whoever follows me will not walk in darkness but will have the light of life"). Walking before God in the light is the full goal of the rescued life.</p>',
  },
  "57": {
    "1": '<p>The superscription contains two titles: <em>al-tašḥēt</em> (Do Not Destroy — a tune name also used for Pss 58–59; cf. the vintage-song in Isa 65:8) and <em>miktam of David when he fled from Saul in the cave</em> — referring to either the cave of Adullam (1 Sam 22:1) or En Gedi (1 Sam 24:3). Both caves were places of refuge during Saul\'s pursuit. "Shadow of your wings" (<em>bĕṣēl kĕnāpêkā</em>) is specifically temple imagery: the cherubim of the ark of the covenant spread their wings over the mercy seat (Exod 25:20; 37:9), creating a "shadow" of divine protection over the most sacred space. To take shelter under YHWH\'s wings is to enter the sanctuary\'s protective space — wherever the speaker is, the temple\'s covering extends. The formula reappears in Pss 17:8; 36:7; 61:4; 63:7; 91:4.</p>',
    "2": '<p>"I cry out to God Most High, to God who carries out his purpose for me" — <em>ʾEl ʿelyôn</em> (God Most High) is the ancient title used by Melchizedek of Salem (Gen 14:18–22), who blessed Abraham as creator of heaven and earth. The title predates specifically Israelite theology and was a shared ANE designation for the supreme deity — used in Ugaritic texts for El as head of the divine council. Israel\'s appropriation of this title claimed that YHWH is that Most High God. "Who carries out his purpose for me" (<em>gōmēr ʿālay</em>) — <em>gāmar</em> means to bring to completion, to perform fully — the God who finishes what he starts for his covenant people.</p>',
    "3": '<p>"He will send from heaven and rescue me... God will send his steadfast love and his faithfulness" — <em>hăsĕdô weʾămittô</em> (his ḥesed and his faithfulness/truth). This pair is the Sinai self-revelation formula of Exodus 34:6 — "abounding in steadfast love and faithfulness" — now understood as two divine attributes sent from heaven on a rescue mission. In the Psalter\'s theology, divine rescue is not arbitrary power but an expression of the specific character God revealed at Sinai: covenant-loyal love and unfailing truthfulness. The formula reappears in Ps 40:11; 57:10; 61:7; 85:10; 89:14; 115:1; 138:2.</p>',
    "4": '<p>"My soul is surrounded by lions; I must lie down among those who breathe fire — human beings whose teeth are spears and arrows and whose tongue is a sharp sword" — the enemies are described through overlapping animal and weapon metaphors. Lions (<em>lĕbāʾîm</em>, powerful lions) surround the speaker; their fiery breath (<em>lahăṭîm</em>, the ones who kindle/inflame — possibly an Aramaic loanword) may be a metaphor for harsh, scalding words. The teeth-as-weapons image (spears, arrows, swords) is shared with Ps 55:21 and Joel 1:6 — the mouth weaponized. In both legal and military contexts, the tongue was understood as a lethal instrument in ANE culture (Prov 12:18; 25:18; Ps 64:3).</p>',
    "5": '<p>"Be exalted above the heavens, O God; let your glory be over all the earth!" — the first occurrence of the liturgical refrain (repeated in v. 11) that frames the psalm. <em>Rûm ʿal-hašāmayim ʾĕlōhîm ʿal kol-hāʾāreṣ kĕbôdekā</em>. The prayer calls for divine exaltation above the entire created order — heavens and earth together. <em>Kābôd</em> (glory, weightiness, presence) is the visible manifestation of divine majesty that filled the tabernacle (Exod 40:34–35) and temple (1 Kgs 8:11) at their dedications. The refrain at the psalm\'s center and close creates a bracket of cosmic doxology around the lament — the crisis is placed within the larger frame of universal divine sovereignty.</p>',
    "6": '<p>"They spread a net for my feet; my soul was beaten down; they dug a pit in my path, but they themselves have fallen into it" — the trap-and-pit imagery describes deliberate ambush. The pivotal reversal in the second half of the verse employs what scholars call the "boomerang motif" — the trap laid for the innocent catches the trapper instead (Pss 7:15–16; 9:15–16; 35:7–8; Prov 26:27; Eccl 10:8). This is not coincidence in the Psalter\'s theology but the structural logic of covenant justice: those who deploy wickedness against the righteous find that their weapons turn against themselves. The pattern is eschatological as well as historical — the final reversal is guaranteed even when not yet visible.</p>',
    "7": '<p>"My heart is fixed, O God, my heart is firm; I will sing and make melody!" — <em>nākôn libbî</em> (my heart is established, firm, resolved). The word <em>nākôn</em> (from <em>kûn</em> — to be established, set firmly) is a technical term for structural stability: a throne that is established, a kingdom that is founded, a person who is settled rather than wavering. The fixed heart of v. 7 contrasts with the "writhing heart" of Ps 55:4 — the movement within this cluster of Psalms is from interior turmoil to interior stability. The decision to sing and make music (<em>ʾāšîrāh waʾăzammĕrāh</em>) follows from the fixed heart — resolved trust produces worship.</p>',
    "8": '<p>"Awake, my honor! Awake, harp and lyre! I will rouse the dawn!" — <em>ʾāʿîrāh hašāḥar</em> (I will rouse the dawn). The speaker addresses his own "honor" (<em>kābôd</em> — probably the soul or spirit; cf. Pss 7:5; 16:9; 30:12; 108:1) to wake for praise. Then the musical instruments are addressed — a personification that animates the worship setting. The climactic statement, "I will rouse the dawn," reverses the expected relationship: normally the dawn wakes the sleeping human; here the praising human wakes before dawn, so eager for worship that he anticipates the sunrise. Dawn (<em>šāḥar</em>) was the appointed time of divine rescue in the Psalter (Ps 46:5; 90:14; Lam 3:23) — the psalmist rises to meet it.</p>',
    "9": '<p>"I will give you thanks, O Lord, among the peoples; I will sing your praise among the nations" — the scope of praise is universal: <em>ʿammîm</em> (peoples, ethnic groups) and <em>lĕʾummîm</em> (nations). This verse is quoted by Paul in Romans 15:9 as evidence that the OT itself anticipated Gentile participation in Israel\'s praise of God — "as it is written: \'Therefore I will praise you among the Gentiles, and sing to your name.\'" The universality of the psalm\'s praise aligns with the Psalter\'s vision (Ps 22:27–31; 47:1–9; 96:3; 98:2–3) of all nations ultimately drawn into the worship of YHWH.</p>',
    "10": '<p>"For your steadfast love reaches to the heavens, your faithfulness to the skies" — <em>ḥasdĕkā ʿad šāmāyim weʾămittĕkā ʿad šĕḥāqîm</em>. The cosmic dimensions of divine attributes: <em>ḥesed</em> (steadfast love) stretches to the heavens; <em>ʾĕmet</em> (faithfulness/truth) reaches to the skies (<em>šĕḥāqîm</em> — the clouds or atmosphere). The vertical measurement is not merely hyperbolic — it asserts that the divine character is as foundational and encompassing as the heavens themselves. This verse is nearly identical to Ps 36:5, where the same cosmic measurement describes <em>ḥesed</em> and <em>ʾĕmûnāh</em> alongside God\'s righteousness as deep as the great abyss.</p>',
    "11": '<p>The liturgical refrain of v. 5 repeated verbatim: "Be exalted above the heavens, O God; let your glory be over all the earth!" This closing return to the doxological frame encloses the entire psalm within a bracket of praise. The structure — refrain / lament and trust / refrain — models a movement that Second Temple liturgy would formalize: crisis held within the larger container of divine sovereignty and worship. Psalms with this envelope structure (also Ps 8, 46, 107, 118) demonstrate that the Psalter\'s editors shaped individual psalms into theological arguments through structure as much as through content.</p>',
  },
  "58": {
    "1": '<p>The superscription repeats the <em>al-tašḥēt miktam of David</em> formula from Ps 57. The opening address is contested: "Do you indeed decree what is right, you <em>ʾĕlōhîm</em>?" The plural <em>ʾĕlōhîm</em> could refer to human judges (as in Exod 21:6; 22:8–9, where judges are called <em>ʾĕlōhîm</em>) or to divine council members — supernatural beings charged with governing the nations (Deut 32:8 LXX; Ps 82:1–6; Dan 10:13). If the divine council interpretation is correct, the Psalm is a prophetic address to heavenly overseers who have allowed injustice to flourish on earth — a tradition prominent in Psalm 82 (where God judges the divine council for failing to uphold justice: "How long will you judge unjustly?"). Either way, the poem is a prophetic denunciation of unjust rulers, human or divine.</p>',
    "2": '<p>"No — in your heart you devise wrongs; your hands administer violence throughout the land" — the interior origin of injustice: <em>bĕlēb ʿawlōt tipʿāllûn</em> (in your heart you work wickednesses). The corruption of justice begins not in ignorance but in the heart — a deliberate choice to use authority for violence. "Throughout the land (<em>bāʾāreṣ</em>)" — the scope is comprehensive; this is not localized corruption but systemic. In covenant theology, rulers were to be agents of divine justice; rulers who devise evil from the heart have become anti-covenant figures, using their office as a weapon against the very people they were appointed to protect (Deut 17:14–20; 1 Sam 8:10–18).</p>',
    "3": '<p>"The wicked are alienated from the womb; from their very birth they go astray, speaking lies" — <em>zōrû rĕšāʿîm mēraḥem</em> (the wicked are estranged from the womb). This verse asserts the deep-rootedness of wickedness in those who practice it — not a surface habit but a condition present from birth. This is a wisdom observation about observed human nature, not a systematic statement about infant guilt. The verse has a parallel in Ps 51:5 ("I was sinful at birth, sinful from the time my mother conceived me") — both acknowledge that human moral formation begins before conscious choice. "Speaking lies" (<em>dōbĕrê šāqer</em>) identifies the characteristic expression of this inborn tendency: falsehood as the natural language of the estranged heart.</p>',
    "4": '<p>"Their venom is like the venom of a snake; they are like the deaf cobra that blocks its ear" — the serpent imagery develops from the falsehood of v. 3 into a specific zoological metaphor. In ANE culture, snake charming was a known practice (Eccl 10:11; Jer 8:17); the "deaf cobra" (<em>pethen ḥērēš</em>) was the species that could not be charmed — notoriously dangerous precisely because it could not be controlled by the charmer\'s music. The image is of a governing class so thoroughly committed to injustice that even prophetic rebuke has no effect on them — they are immune to the word that would normally call them to account.</p>',
    "5": '<p>"That will not listen to the voice of those who charm, no matter how skillfully they do it" — <em>ʾăšer lōʾ-yišmaʿ lĕqôl mĕlaḥăšîm ḥôbēr ḥăbārîm mĕḥukkām</em>. The "charmer" (<em>mĕlaḥaš</em>, whisperer, charmer) uses specific skill to redirect dangerous creatures — in the social world, this figure represents the wise counselor or prophet who uses speech to guide those in power. The reference to skill ("no matter how skillfully") emphasizes that this is not a failure of technique but a resistance to wisdom itself. Jeremiah 8:17 uses the same image for the Babylonian army that cannot be charmed away from judgment: "For I am going to send venomous snakes among you — adders that cannot be charmed, and they will bite you."</p>',
    "6": '<p>"Smash their teeth in their mouths, O God; tear out the fangs of the young lions, O LORD!" — the imprecation targets the specific instruments of the wicked\'s predation: their teeth and fangs. In Psalm 34:10, "young lions (<em>kĕpîrîm</em>)" may go hungry while those who fear YHWH lack nothing — here the imprecation reverses their predatory capacity. Disabling the teeth is disabling the weapon: the judicial violence the wicked administer through their rulings (v. 2) is expressed through the lion-tooth metaphor. The prayer is for the wicked to become what they cannot avoid being without their power — harmless, without the instruments of domination.</p>',
    "7": '<p>"Let them drain away like water flowing downhill; when they draw their bows, let their arrows fall harmless" — the sequence of similes in vv. 7–9 piles up images of futility and dissolution. Water flowing away is irreversible — it cannot be gathered back once it runs off. The image of arrows falling harmless mid-flight inverts the military power of the armed warrior: the bow is drawn, the moment of maximum threat, yet the arrow accomplishes nothing. In the Psalter\'s theology of divine reversal, the powerful are made impotent and the weapons of the wicked misfire in God\'s presence (Ps 76:3–6).</p>',
    "8": '<p>"Let them be like a snail that dissolves as it goes, like a stillborn child that never sees the light of the sun" — the snail (<em>šablûl</em>) was observed in antiquity to leave a trail of slime as it moved, which observers interpreted as the creature dissolving itself away. This is not accurate zoology but is a vivid image of self-consuming dissolution. The <em>nepel</em> (stillborn child, or premature birth that does not survive) was in the ancient world a symbol of complete failure to reach life\'s potential — conceived but never able to develop (Job 3:16; Eccl 6:3). The comparison positions the wicked as beings who reach neither full life (like the stillborn) nor lasting presence (like the dissolving snail).</p>',
    "9": '<p>"Before your cooking pots have felt the heat of the thornwood — both green and dry — he will whirl them away" — one of the most difficult verses in the Psalter; the image is of a fire that is extinguished before it even heats the cooking pots. Thornwood burns hot but briefly — it catches quickly and dies quickly. The "both green and dry" (<em>ḥay wĕḥārôn</em>) may indicate thorns at different stages of readiness, which together still cannot sustain the fire long enough to complete the cooking. The point: the wicked will be swept away before their schemes are completed, before their destructive energy has accomplished anything. The divine judgment is faster than their plans.</p>',
    "10": '<p>"The righteous will rejoice when they see justice carried out; they will wash their feet in the blood of the wicked" — this verse is among the most troubling imprecatory images for modern readers. The washing of feet in the blood of enemies echoes the ANE battle context: victorious warriors waded through the blood of the slain (cf. Isa 63:1–6; Rev 14:20; 19:13–15). This is covenant curse imagery — the language of Deuteronomy 28\'s curses applied to those who have oppressed the innocent. In the ancient world of covenant treaties, curse formulas were graphic and visceral by design — they were meant to convey the severity of the covenant-breaking. The righteous rejoicing (<em>yiśmaḥ ṣaddîq</em>) is the vindication of those who suffered under unjust rulers.</p>',
    "11": '<p>"Then people will say, \'There really is a reward for the righteous; truly there is a God who judges the earth\'" — the theological conclusion is the payoff of the entire psalm. The skeptics who doubted divine justice (implied throughout) will be silenced by the visible evidence. "A reward for the righteous (<em>pĕrî laṣṣaddîq</em>)" — fruit, concrete result — validates the wisdom tradition\'s claim that righteous living produces good outcomes under divine governance. "A God who judges (<em>šōpĕṭîm</em>) the earth" — the governing title for the deity who holds final authority over earthly justice. The concluding verse answers the opening question (v. 1: do you rulers decree what is right?) by asserting that if they do not, God does.</p>',
  },
  "59": {
    "1": '<p>The superscription links Psalm 59 to 1 Samuel 19:11–18: Saul sent agents to watch David\'s house through the night to kill him at dawn; Michal, David\'s wife, warned him and helped him escape through a window, putting a household idol in his bed as a decoy. The threat was specifically nocturnal — hence the "howling like dogs circling the city" imagery of vv. 6 and 14, which describes the watchers prowling around the house in the night. The personal and political situation is acute: the king himself has issued the kill order, so normal legal or social protections are unavailable. Psalm 59 is the third consecutive psalm using the <em>al-tašḥēt miktam</em> formula, grouping it with Pss 57–58 as a cluster of Davidic laments from the persecution period.</p>',
    "2": '<p>"Rescue me from those who do evil, and save me from men who want my blood" — <em>ʾanšê dāmîm</em> (men of blood, men who want bloodshed) is a characteristic Psalter phrase for those whose defining activity is lethal violence (Pss 5:6; 26:9; 55:23; 139:19). In the covenant legal system, shedding innocent blood was the gravest offense against the covenant community — blood pollution defiled the land itself and required judicial atonement (Num 35:33–34). To be threatened by "men of blood" was to be in a situation where the entire protective structure of covenant law had been subverted by the very ruler who should have enforced it.</p>',
    "3": '<p>"For see — they lie in ambush for my life; fierce men are gathering against me — not for any offense or sin of mine, LORD" — the protestation of innocence (<em>bĕlōʾ-pešaʿ ûbĕlōʾ ḥaṭṭāʾtî</em>) is a standard element of the individual lament and echoes the legal context of the Psalter\'s prayers. The speaker is not claiming sinlessness in a general moral sense but legal innocence in this specific case — there is no offense that would justify the attack. "Fierce men (<em>ʿazzîm</em>)" — the powerful and physically formidable who rely on their strength rather than law or justice.</p>',
    "4": '<p>"For no fault of mine they have mobilized against me. Arouse yourself, come to meet me, and look!" — <em>ʿûrāh liqrāʾtî ûrʾēh</em> (arouse yourself, come to meet me, and look). The "awakening" petition addresses what feels like divine inactivity or sleep — a bold appeal to the God who seems to have allowed the injustice to proceed unchecked. The same petition appears in Ps 35:23 ("Stir up yourself and awake for my defense!") and Ps 44:23–26 ("Awake, O Lord! Why are you sleeping?"). The prophetic tradition (Isa 51:9: "Awake, awake, put on strength, O arm of the LORD!") also uses this language for dramatic urgency — the divine warrior called to action.</p>',
    "5": '<p>"You are the LORD God of hosts, the God of Israel — rouse yourself to punish all the nations; show no mercy to those who commit treason with evil intent" — the full title <em>YHWH ʾĕlōhê ṣĕbāʾôt ʾĕlōhê yiśrāʾel</em> (LORD God of hosts, God of Israel) is the most complete military-theological title in the OT, invoking YHWH as commander of the heavenly armies and as the specific covenant God of Israel. The expansion to "all the nations (<em>kol-haggôyim</em>)" is striking — the immediate enemies are Saul\'s agents, yet the prayer addresses a cosmic scope. This move from particular threat to universal justice is characteristic of the Psalter\'s theology: the individual\'s crisis is embedded within the larger divine governance of all nations.</p>',
    "6": '<p>"They return each evening, howling like dogs and circling around the city" — the dog imagery in the ANE context is specifically derogatory. Dogs in the ancient world were primarily urban scavengers — ownerless packs that roamed city streets at night, fighting over refuse and corpses (1 Kgs 14:11; 21:23–24; 2 Kgs 9:10). To compare enemies to dogs was to portray them as dishonored, scavenging, unclean. The nocturnal timing ("each evening") fits the superscription\'s narrative of nighttime watchers surrounding the house. The circling motion — howling and prowling — describes the surveillance of Saul\'s agents waiting to close in at dawn.</p>',
    "7": '<p>"Listen — they pour out venom with their mouths; their lips are full of swords, for they think, \'Who is going to hear?\'" — <em>nābaʿ bĕpîhem</em> (they pour out/bubble up with their mouths) — the verb describes the overflow of a spring or a bubbling up of language that cannot be contained. "Lips full of swords" repeats the weapon-mouth imagery of Ps 57:4 and Ps 55:21. The enemies\' confidence — "who is going to hear?" (<em>mî šōmēaʿ</em>) — is the assumption that they are unobserved and unaccountable. This is the psalmist\'s most devastating indictment: the wicked sin because they believe God does not see or hear. The Psalter\'s response is that YHWH hears precisely what they say when they think no one is listening (Ps 94:7–11).</p>',
    "8": '<p>"But you, LORD, laugh at them; you scoff at all the nations" — the divine laughter (<em>yiśḥaq ... yilʿag</em>) here echoes Psalm 2:4, where YHWH laughs at the conspiracy of the nations against his anointed king. The laugh is not frivolous but expresses the sovereign\'s confident contempt for those who imagine their schemes can succeed against the divine governance. In the ANE, laughter was a weapon of superior power — the patron who could afford to laugh at a threat was demonstrating that the threat posed no real danger to his position. YHWH\'s laughter at the nations\' plots is an implicit guarantee of the psalmist\'s safety.</p>',
    "9": '<p>"O my Strength, I will wait on you; for God is my fortress" — <em>ʿuzzî</em> (my strength) is used here as a divine title — the psalmist has internalized YHWH\'s character as his personal attribute. This divine-title pattern (my strength, my rock, my fortress, my shepherd, my light) is distinctive to the Psalter\'s personal theology: the abstract attributes of God become the first-person possession of the covenant worshipper. <em>Miśgāb</em> (fortress, high refuge, inaccessible stronghold) is frequently applied to YHWH in the Psalter (Pss 9:9; 18:2; 46:7, 11; 48:3; 62:2, 6; 94:22; 144:2) — the image of a natural high fortification that cannot be taken by assault.</p>',
    "10": '<p>"The God of my steadfast love will come ahead of me; God will let me look in triumph on my enemies" — <em>ʾĕlōhê ḥasdî</em> (God of my steadfast love — God who is the source of loyal-love toward me) personifies <em>ḥesed</em> as the defining attribute of the divine-human relationship. "Will come ahead of me" (<em>yĕqaddĕmēnî</em>) — <em>qādam</em> (to go before, to come in advance) is the language of divine guidance as a vanguard: God goes ahead of the speaker into the encounter with enemies. The scout or advance party provides intelligence and clears the path — YHWH as the one who prepares the ground before the covenant worshipper enters it (Exod 23:20; 33:14; Deut 31:8).</p>',
    "11": '<p>"Do not kill them, so my people will not forget; bring them down by your power and humble them, O Lord our shield!" — one of the most theologically distinctive petitions in the Psalter. The request is for restraint rather than destruction: preserve the enemies as living testimony to divine justice, so Israel will not forget what God did. This pedagogical use of judgment — enemies humbled rather than annihilated — functions as a didactic sign for the community. A similar logic appears in Exodus 9:16, where YHWH tells Pharaoh that he has been "raised up" specifically so that God\'s power might be displayed and his name proclaimed throughout all the earth. Obliteration of the wicked removes the witness; their humbling preserves it.</p>',
    "12": '<p>"For the sin of their mouths and the words of their lips, let them be ensnared in their own pride. For the cursing and deception that they utter" — speech is the vehicle of their sin: <em>ḥaṭṭāʾt pîmô dĕbar śĕpātêmô</em> (the sin of their mouth, the word of their lips). The prayer is that the very speech that is their weapon becomes the snare that catches them — the "own pride" (<em>gĕʾônām</em>) of confident self-assertion ensnares them. The OT principle that the wicked are caught by their own devices (Pss 7:15; 9:15; Prov 5:22; 11:5) is here applied specifically to linguistic pride and deception.</p>',
    "13": '<p>"Consume them in your wrath; consume them until they are no more, so that people may know that God rules over Jacob to the ends of the earth" — the universalizing conclusion: the purpose of divine judgment is knowledge (<em>wĕyēdĕʿû</em>), not merely satisfaction of justice. "God rules over Jacob to the ends of the earth" — the specific covenant identity (Jacob/Israel) is proclaimed universally; YHWH\'s lordship over his covenant people is the content of the knowledge that should reach the world\'s boundaries. This missional dimension of judgment runs through the Psalter: divine acts on behalf of Israel become the proclamation of YHWH\'s universal sovereignty (Pss 46:10; 98:2–3; Isa 49:6).</p>',
    "14": '<p>The dog refrain returns verbatim from v. 6: "They return each evening, howling like dogs and circling the city." The structural repetition of this refrain (vv. 6 and 14) creates a framing device for the psalm\'s middle section of trust and petition. The repetition also makes a theological point: the threat has not disappeared — the enemies are still prowling. But the speaker\'s inner state has changed from vulnerable pleading (vv. 1–7) to confident trust (vv. 9–13). The same external circumstance is now viewed from a different interior position.</p>',
    "15": '<p>"They roam around in search of food; they growl when they are not satisfied" — the nocturnal scavenging of the dog-enemies continues into the daybreak watch. <em>Yĕnaʿû lĕʾĕkōl</em> (they wander to eat) and <em>yālînû</em> (they howl/stay the night) — the word <em>lûn</em> can mean both "to spend the night" and "to grumble, mutter." The unsatisfied dogs growling through the night are a portrait of enemies whose schemes have not yielded the kill they sought. Their frustration — the speaker has escaped, they have not gotten their prey — is itself evidence of divine protection operating through Michal\'s warning (in the narrative setting of the superscription).</p>',
    "16": '<p>"But I will sing of your strength; I will sing aloud of your steadfast love in the morning; for you have been my fortress and my place of refuge in my day of distress" — the dawn transition: the night of threat becomes the morning of praise. <em>Ḥasdĕkā</em> (your steadfast love/ḥesed) and <em>ʿozzî</em> (my strength) are the twin themes of the psalm\'s confidence. "In the morning" (<em>babbōqer</em>) is the classic rescue moment in the Psalter (Ps 30:5: "weeping may tarry for the night, but joy comes in the morning"; Ps 46:5: "God will help her when morning dawns"). The divine pattern of night-terror and morning-rescue was liturgically formalized in the temple vigils, where worshippers waited through the night for the morning announcement of divine answer (Ps 130:5–6).</p>',
    "17": '<p>"O my Strength, I will sing praise to you; for God is my fortress, the God who shows me steadfast love" — the closing verse returns to the title <em>ʿuzzî</em> (my Strength) from v. 9, creating an envelope. The three attributes accumulated through the psalm — strength (<em>ʿōz</em>), fortress (<em>miśgāb</em>), and steadfast love (<em>ḥesed</em>) — form the theological summary of what YHWH has been in the speaker\'s crisis. The final characterization "who shows me steadfast love" (<em>ʾĕlōhê ḥasdî</em>, God of my ḥesed) personalizes the covenant relationship: this is not generic divine beneficence but the specific, directed loyal-love of the covenant God toward this particular person in this particular crisis.</p>',
  },
  "60": {
    "1": '<p>Psalm 60 has the most historically detailed superscription in the Psalter: it links to the campaigns of 2 Samuel 8:3–13 and 1 Chronicles 18:3, 12–13, in which David fought the Aramean kingdoms and Joab defeated twelve thousand Edomites in the Valley of Salt (south of the Dead Sea). The psalm is unusual among Davidic psalms in being a community lament after a military defeat — evidence that not all of David\'s campaigns were immediately victorious. "Lily of the Testimony" (<em>šûšan ʿēdût</em>) is a tune title; the word <em>ʿēdût</em> (testimony, covenant law) is also used for the ark of the covenant (<em>ʾārôn hāʿēdût</em>), giving the title a covenantal resonance. Psalm 60 is largely duplicated in Psalm 108:6–13, showing that individual psalms were reused in new collections and contexts.</p>',
    "2": '<p>"You have made the earth shake; you have cracked it open; heal its fractures, for it is collapsing" — the earthquake (<em>hirʿaštāh ʾereṣ</em>, you made the earth shake) is the standard language of theophany and divine judgment in the OT (Pss 18:7; 29:8; 68:8; 77:18; Hab 3:10). Applied to military defeat, the metaphor is precise: the defeat felt as if the very ground of national security had cracked open. "Heal its fractures" (<em>rĕpāʾāh šĕbārêhā</em>) — the same healing language applied to a broken land as to a broken person (Ps 147:3: "he heals the brokenhearted and binds up their wounds"). The petition for healing the land echoes the Solomonic prayer (2 Chr 7:14: "if my people who are called by my name humble themselves... then I will heal their land").</p>',
    "3": '<p>"You have put your people through severe trials; you have made us drink disorienting wine" — <em>yên tarʿēlāh</em> (wine of staggering/reeling). In the prophetic literature, the "cup" that YHWH hands the nations or Israel to drink is a standard metaphor for judgment and catastrophe (Isa 51:17–22; Jer 25:15–29; Ezek 23:31–34; Hab 2:16; Rev 16:19). The wine does not intoxicate with pleasure but with confusion and loss of capacity — the military defeat has left the community disoriented, unable to assess the situation clearly. "You have put your people through severe trials" (<em>hirʾîtānû qāšôt</em>) — the acknowledgment that the testing came from God, not merely from the enemy, is theologically significant: it frames the defeat as covenant discipline rather than divine abandonment.</p>',
    "4": '<p>"You have set up a banner for those who fear you, for them to rally to in the face of the enemy\'s bow" — <em>nēs</em> (battle standard, signal flag) was the pole or marker around which dispersed troops or people were to gather (Isa 5:26; 11:10, 12; 62:10; Jer 4:21). The military metaphor: in the chaos of battle, the standard shows troops where the rallying point is. The prayer is that YHWH has established such a banner — that the defeat has not scattered the community beyond recovery but that God has provided a visible gathering point. "Those who fear you (<em>lĕyirʾêkā</em>)" — the covenant community defined by <em>yirʾat YHWH</em>, used throughout the Psalter as the hallmark of the faithful.</p>',
    "5": '<p>"Save your dear ones — rescue them by your right hand, and answer our prayer" — <em>yĕdîdêkā</em> (your beloved ones, your dear ones) — the term for those who stand in a relationship of special affection with YHWH. The same word characterizes Benjamin as "beloved of YHWH" (Deut 33:12) and Solomon as <em>Yĕdîdyāh</em> (loved by YHWH, 2 Sam 12:25). "Your right hand" (<em>yĕmînĕkā</em>) is the instrument of divine power and victory (Exod 15:6, 12; Ps 18:35; 44:3; 98:1). The appeal combines affection (beloved ones) and power (right hand) as the two grounds for rescue — YHWH acts because he loves Israel and because he has the power to save.</p>',
    "6": '<p>"God has spoken in his holiness: \'I will triumph; I will divide up Shechem and portion out the Valley of Succoth\'" — <em>dibber bĕqodšô</em> (God has spoken in his holiness/sanctuary). The oracle begins: YHWH speaks from his sanctuary (<em>qōdeš</em> can be either the divine attribute of holiness or the sanctuary as its location — probably the former here, giving the oracle divine-character authority). The oracle asserts YHWH\'s territorial sovereignty over the promised land: Shechem (the central highland city, site of covenant assemblies in Josh 24) and Succoth (in the Transjordan Jordan valley, east of the Jordan) together represent the breadth of the land — west and east of the Jordan.</p>',
    "7": '<p>"\'Gilead is mine, Manasseh is mine; Ephraim is my helmet; Judah is my scepter\'" — the oracle continues distributing the territories. Gilead (Transjordan highland) and Manasseh (the largest tribe, split across both sides of the Jordan) bracket the Transjordanian territory. Ephraim (the most powerful northern tribe) is YHWH\'s "helmet" (<em>māʿôz rōʾšî</em>, literally "stronghold of my head") — the military protection of the divine warrior\'s head, possibly referring to Ephraim\'s geographical position protecting the north. Judah is YHWH\'s "scepter" (<em>mĕḥōqĕqî</em>, my lawgiver/ruler\'s staff) — the royal tribe through which the covenant line of authority runs (Gen 49:10: "the scepter will not depart from Judah").</p>',
    "8": '<p>"\'Moab is my washbasin; over Edom I throw my sandal; over Philistia I shout in triumph\'" — the three neighboring peoples who were traditional enemies of Israel are reduced to servile objects. Moab as a "washbasin" (<em>sîr raḥṣî</em>) — a servant\'s vessel for washing feet, the most menial of household implements. Edom: the sandal-throw has two possible meanings: (1) asserting ownership by throwing a sandal onto property (cf. Ps 108:9, Ruth 4:7–8, where the sandal gesture marks a transfer of property rights); (2) contemptuous dismissal — flinging a sandal at someone. Both meanings converge in a gesture of complete domination. Philistia, historically Israel\'s most persistent military threat, is simply shouted over in triumph (<em>hitroʿaʿtî</em>) — reduced to an object of a victory cry.</p>',
    "9": '<p>"Who will bring me into the fortified city? Who will guide me all the way to Edom?" — the "fortified city" (<em>ʿîr māṣôr</em>) almost certainly refers to Sela (Petra), the Edomite rock city in the southern Transjordan — approached through narrow canyon passes and nearly impregnable. This is the capital of the territory YHWH has just claimed in the oracle (v. 8). The question signals military realism: even with the divine oracle asserting territorial ownership, taking the fortified city requires a guide and divine accompaniment into hostile territory. The prayer moves from oracle (vv. 6–8) to practical military petition (vv. 9–12).</p>',
    "10": '<p>"Have you not rejected us, O God? You no longer go out, God, with our armies" — <em>hălōʾ ʾattāh ʾĕlōhîm zĕnaḥtānû wĕlōʾ-tēṣēʾ ʾĕlōhîm bĕṣibʾôtênû</em>. The divine warrior\'s absence from battle was the most catastrophic possibility in covenant theology (cf. 2 Sam 5:24, where YHWH\'s "going out ahead of you" is the signal to attack; and Deut 20:4, where YHWH\'s going with the army is the basis for fearlessness in battle). The defeat of v. 1 is here interpreted as YHWH "not going out" with the armies — the divine military presence withdrawn as a covenant consequence. This is not doubt but honest liturgical wrestling with the experience of divine absence.</p>',
    "11": '<p>"Give us help against the enemy, for human deliverance is worthless" — <em>šāwʾ tĕšûʿat ʾādām</em> (vain/empty is the salvation that comes from ʾādām, mortal humans). The word <em>šāwʾ</em> (vanity, emptiness, worthlessness) is the key term of Ecclesiastes (translated "vanity") and appears throughout the Psalter as the characterization of what human strength alone can achieve without divine backing. The military conclusion is that no human alliance, strategy, or strength can succeed where YHWH has withdrawn. This is a radical statement of military theology: the only reliable source of deliverance is the covenant God, and any confidence placed elsewhere is <em>šāwʾ</em>.</p>',
    "12": '<p>"Through God we will do great deeds; he himself will crush our enemies" — the psalm ends in confident assertion despite the lament: <em>bĕʾĕlōhîm naʿăśeh ḥāyil wĕhûʾ yābûs ṣārênû</em>. The transition from "God has rejected us" (v. 10) to "through God we will do great deeds" (v. 12) is not logically resolved within the psalm — the oracle of vv. 6–8 provides the basis for the confidence, but the defeat of vv. 1–3 is still present. This is the Psalter\'s characteristic liturgical move: bringing complaint and confidence into proximity without eliminating the tension, trusting that the God who spoke the oracle is the same God who permitted the defeat, and that both are within his governance. The final word is "he himself will crush our enemies" — active divine intervention completing what human strength cannot.</p>',
  },
  "61": {
    "1": '<p>Psalm 61 is one of the shortest Davidic psalms — eight verses — but dense with the Psalter\'s characteristic vocabulary of refuge and royal prayer. The superscription specifies <em>nĕgînāh</em> (singular — a single stringed instrument, in contrast to the plural <em>nĕgînôt</em> of Ps 55:1), suggesting intimate performance rather than full ensemble. The shift in vv. 6–7 from first-person prayer to third-person prayer for "the king" has led some interpreters to see two distinct voices — an individual worshipper and a court liturgy for the king — or to read the psalm as the king praying about himself in the third person (a practice found in ancient court documents).</p>',
    "2": '<p>"From the ends of the earth I call out to you when my heart grows faint" — <em>miqqĕṣēh hāʾāreṣ</em> (from the end of the earth). This phrase does not necessarily indicate literal geographical distance; it is the Psalter\'s language for extreme alienation from the divine presence concentrated in Jerusalem\'s temple. When Lamentations describes the exiled community, it uses similar language of felt distance from YHWH. The "faint heart" (<em>bĕ-ʿāṭap libbî</em>) — the <em>ʿāṭap</em> verb means to be wrapped up, overwhelmed, covered over — the spirit muffled by distress. "Lead me to the rock that is higher than I" (<em>sûr yārûm mimmennî</em>) — the inaccessible high rock that the distressed person cannot reach by their own strength; they must be guided there. God as the high refuge is not automatically accessible to the desperate — it requires divine escort.</p>',
    "3": '<p>"For you have been a shelter for me, a strong tower against the enemy" — <em>maḥseh lî</em> (a refuge/shelter for me) and <em>migdal ʿōz</em> (tower of strength, strong tower). The strong tower was a specific ANE defensive structure — a tall, narrow fortification built within or near a city that served as a last refuge when the city walls were breached. Judges 9:51 describes the people of Shechem fleeing to such a tower during Abimelech\'s attack; 2 Kings 9:17 mentions a watchtower lookout. Applied to YHWH, the tower image captures both height (inaccessibility to enemies) and strength (structural invulnerability). "Against the face of the enemy" (<em>mipnê ʾôyēb</em>) — the tower faces the threat directly.</p>',
    "4": '<p>"I will dwell in your tent forever; I will take refuge under the shelter of your wings" — <em>ʾāgûrāh bĕʾāhŏlĕkā ʿôlāmîm</em> (I will sojourn in your tent forever). The "tent" (<em>ʾōhel</em>) is the tabernacle or temple in its portable-sanctuary form — the dwelling place of YHWH\'s presence. Permanent dwelling in the tent is the psalmist\'s ultimate aspiration (Ps 23:6: "I shall dwell in the house of the LORD forever"; Ps 27:4: "one thing I have asked of the LORD — that I may dwell in the house of the LORD all the days of my life"). "Under the shelter of your wings" (<em>bĕsēter kĕnāpêkā</em>) — the cherubim wing imagery also present in Ps 57:1. The wings of the cherubim over the ark (<em>kappōret</em>) form the protective "shadow" of divine presence; to be under those wings is to be within the sacred space of covenant relationship.</p>',
    "5": '<p>"For you, O God, have heard my vows; you have given me the inheritance of those who fear your name" — the <em>nĕdārayim</em> (vows) confirms the setting: the psalmist has made solemn pledges to God during the crisis described in vv. 2–4, and now the divine response is being acknowledged. "The inheritance (<em>yĕrušāh</em>) of those who fear your name" — to receive the inheritance of the covenant community is to be incorporated into the people of God as a full beneficiary of covenant promises. The "those who fear your name" (<em>yirʾê šĕmekā</em>) is the standard designation for the covenant community throughout the Psalter and Malachi 3:16. The psalmist is confirmed as belonging to this circle.</p>',
    "6": '<p>"You will extend the king\'s days; his years shall span many generations" — the shift to third person: "the king (<em>hammelek</em>)" rather than "I." This is a prayer for the Davidic king\'s longevity, a standard element of ancient Near Eastern royal liturgy. Egyptian and Mesopotamian royal hymns regularly included prayers for the king to live "millions of years," often in specifically hyperbolic terms. In Israel\'s covenant theology, the king\'s longevity was covenantally conditioned on covenant faithfulness (Deut 17:20; 1 Kgs 3:14; Ps 21:4; 72:5, 17). "Many generations (<em>kĕdôr wādôr</em>)" — the phrase used in the Psalter for the covenant faithfulness of God extended to successive generations (Pss 33:11; 89:1, 4; 102:24; 135:13); here applied to the king as covenant representative.</p>',
    "7": '<p>"May he dwell before God forever; appoint steadfast love and faithfulness to guard him" — <em>yēšēb ʿôlām lipnê ʾĕlōhîm</em> (may he dwell forever before God). Dwelling "before God (<em>lipnê ʾĕlōhîm</em>)" is the language of priestly and royal access to the divine presence — the sanctuary as the space where one stands before YHWH. The king mediates between the divine and human realms; his continued "dwelling before God" ensures the covenant relationship remains intact for the whole community. "Steadfast love and faithfulness (<em>ḥesed weʾĕmet</em>) appointed to guard him" — the divine attributes from the Sinai self-revelation (Exod 34:6) are personified as sentinels posted to protect the king. This is the inverse of Ps 91:11 (angels commanded to guard); here the covenant attributes themselves are the guardians.</p>',
    "8": '<p>"So I will sing praise to your name forever, as I fulfill my vows day after day" — the closing verse returns to the first person, completing the movement from distress (v. 2) through confidence in divine provision (vv. 3–7) to ongoing worship (v. 8). "To sing praise to your name (<em>ʾăzammĕrāh šĕmĕkā</em>) forever" — the permanent vocation of the delivered worshipper is praise, not mere relief. "Fulfill my vows day after day (<em>lĕšallēm nĕdāray yôm yôm</em>)" — the plural <em>nĕdāray</em> (my vows) and the repetitive time marker "day after day" suggest ongoing liturgical practice: the psalm of thanksgiving was not a one-time event but a rhythm of continued grateful remembrance. The fulfilled vow embedded the rescue permanently in the worshipper\'s life through repeated rehearsal.</p>',
  }
}

# INTENT: mkt-context for Psalms 55–61 — six Davidic laments from the Saul-persecution period
#   plus one community lament (Ps 60); covers betrayal theology (Ps 55), divine record of tears (Ps 56),
#   dawn-praise theology (Ps 57), unjust rulers (Ps 58), divine laughter at conspirators (Ps 59),
#   territorial oracle (Ps 60), and king-prayer liturgy (Ps 61).
# CHANGE? If mkt-context/psalms.json structure changes, update load_comm/save_comm source string.
# VERIFY: python3 -c "import json; d=json.load(open('data/commentary/mkt-context/psalms.json'));
#   print('55 v13:', d.get('55',{}).get('13','MISSING')[:80])"

def main():
    existing = load_comm('mkt-context', 'psalms')
    merge_comm(existing, PSALMS)
    save_comm('mkt-context', 'psalms', existing)
    total = sum(len(v) for v in existing.values())
    print(f'Psalms mkt-context: {len(existing)} chapters, {total} verse entries total')
    print('Psalms 55–61 mkt-context written.')

if __name__ == '__main__':
    main()
